+            <p>Broj telefona: {selectedTerm.term?.rezervirao || "Nepoznat"}</p>
+            <p>Vrijeme: {selectedTerm.term?.od} - {selectedTerm.term?.do}</p>
+            <p>Datum: {formatDate(selectedTerm.term?.datum)}</p>
+            <p>
+              Usluga:{" "}
+              {salon?.usluge?.find((u) => u.id === selectedTerm.term?.usluga_id)?.naziv || "Nepoznato"}
+            </p>
+            <button className="cancel-reservation-btn" onClick={() => selectedTerm?.term?.rezervirao && onCancel(selectedTerm.term)}>
+              Otkaži termin
+            </button>
+            <button onClick={() => onFree(selectedTerm.datum, selectedTerm.term,onClose)}>Oslobodi termin</button>
+            <button onClick={onClose}>Zatvori</button>
+          </div>
+        ) : (
+          <ReservationForm
+            selectedTerm={selectedTerm}
+            salon={salon}
